import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import {
  Search, ShoppingBag, User, Menu, X, LogOut, Loader,
  Heart, Bell, Settings, Package, ChevronRight, ChevronDown,
  Globe
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useCart } from '../../context/CartContext';
import { useWishlist } from '../../context/Wishlistcontext';
import { productAPI } from '../../api/api';
import './Navbar.css';

/* ── Supported languages ── */
const LANGUAGES = [
  { code: 'en', label: 'English', flag: '🇬🇧' },
  { code: 'es', label: 'Español', flag: '🇪🇸' },
  { code: 'de', label: 'Deutsch', flag: '🇩🇪' },
  { code: 'fr', label: 'Français', flag: '🇫🇷' },
  { code: 'ja', label: '日本語', flag: '🇯🇵' },
];

export default function Navbar({ onMenuToggle, notificationCount = 0 }) {
  const { user, isAuthenticated, logout } = useAuth();
  const { cart } = useCart();
  const { wishlist } = useWishlist();
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();

  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [showUser, setShowUser] = useState(false);
  const [showLang, setShowLang] = useState(false);
  const [searching, setSearching] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);
  const [searchFocused, setSearchFocused] = useState(false);

  const searchRef = useRef();
  const userRef = useRef();
  const langRef = useRef();
  const timer = useRef();

  /* ── Click-away handler ── */
  useEffect(() => {
    const handler = (e) => {
      if (searchRef.current && !searchRef.current.contains(e.target)) {
        setShowResults(false);
        setSearchFocused(false);
      }
      if (userRef.current && !userRef.current.contains(e.target)) setShowUser(false);
      if (langRef.current && !langRef.current.contains(e.target)) setShowLang(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  /* ── Keyboard shortcut: focus search with "/" ── */
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === '/' && !['INPUT', 'TEXTAREA'].includes(document.activeElement.tagName)) {
        e.preventDefault();
        const searchInput = document.querySelector('.nav-search input');
        if (searchInput) {
          searchInput.focus();
          setSearchFocused(true);
        }
      }
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, []);

  /* ── Search logic ── */
  const handleSearch = (val) => {
    setQuery(val);
    setActiveIndex(-1);
    clearTimeout(timer.current);

    if (val.trim().length < 2) {
      setResults([]);
      setShowResults(false);
      setSearching(false);
      return;
    }

    setSearching(true);
    timer.current = setTimeout(async () => {
      try {
        const res = await productAPI.search(val.trim());
        const data = res.data?.data || [];
        setResults(Array.isArray(data) ? data.slice(0, 6) : []);
        setShowResults(true);
      } catch (err) {
        console.error('Search failed:', err);
        setResults([]);
        setShowResults(true);
      }
      setSearching(false);
    }, 300);
  };

  const handleSearchKeyDown = (e) => {
    if (!showResults || results.length === 0) {
      if (e.key === 'Escape') { setShowResults(false); setSearchFocused(false); }
      return;
    }

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setActiveIndex(prev => (prev < results.length - 1 ? prev + 1 : 0));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setActiveIndex(prev => (prev > 0 ? prev - 1 : results.length - 1));
        break;
      case 'Enter':
        e.preventDefault();
        if (activeIndex >= 0 && results[activeIndex]) {
          navigate(`/products/${results[activeIndex].id}`);
          clearSearch();
        } else if (query.trim()) {
          navigate(`/products?q=${encodeURIComponent(query)}`);
          clearSearch();
        }
        break;
      case 'Escape':
        setShowResults(false);
        setActiveIndex(-1);
        setSearchFocused(false);
        break;
      default:
        break;
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (query.trim()) {
      navigate(`/products?q=${encodeURIComponent(query)}`);
      clearSearch();
    }
  };

  const clearSearch = () => {
    setQuery('');
    setResults([]);
    setShowResults(false);
    setActiveIndex(-1);
    setSearchFocused(false);
  };

  const highlightMatch = (text, q) => {
    if (!text || !q.trim()) return text;
    const regex = new RegExp(`(${q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
    const parts = text.split(regex);
    return parts.map((part, i) =>
      regex.test(part) ? <mark key={i} className="search-highlight">{part}</mark> : part
    );
  };

  /* ── Language switcher ── */
  const handleLanguageChange = (langCode) => {
    i18n.changeLanguage(langCode);
    setShowLang(false);
    // Optional: persist preference
    localStorage.setItem('preferredLanguage', langCode);
  };

  const currentLang = LANGUAGES.find(l => l.code === i18n.language) || LANGUAGES[0];

  return (
    <nav className="navbar">
      {/* ── Left: Menu + Search ── */}
      <div className="nav-left">
        <button className="nav-menu-btn" onClick={onMenuToggle} aria-label={t('nav.toggleMenu', 'Toggle menu')}>
          <Menu size={22} />
        </button>

        <form
          className={`nav-search ${searchFocused ? 'nav-search--focused' : ''}`}
          onSubmit={handleSubmit}
          ref={searchRef}
        >
          <Search size={18} className="search-icon" />
          <input
            type="text"
            placeholder={t('nav.search')}
            value={query}
            onChange={(e) => handleSearch(e.target.value)}
            onFocus={() => {
              setSearchFocused(true);
              if (query.trim().length >= 2 && results.length > 0) setShowResults(true);
            }}
            onKeyDown={handleSearchKeyDown}
            autoComplete="off"
            aria-label={t('nav.search')}
          />

          {/* Keyboard hint */}
          {!searchFocused && !query && (
            <span className="search-kbd" aria-hidden="true">
              <kbd>/</kbd>
            </span>
          )}

          {searching && (
            <span className="search-spinner" aria-label={t('common.loading')}>
              <Loader size={16} className="spin" />
            </span>
          )}
          {query && !searching && (
            <button 
              type="button" 
              className="search-clear" 
              onClick={clearSearch}
              aria-label={t('common.clear', 'Clear search')}
            >
              <X size={16} />
            </button>
          )}

          {showResults && (
            <div className="search-dropdown" role="listbox">
              {results.length > 0 ? (
                <>
                  <div className="search-dropdown-header">
                    <span>{t('nav.searchResults', 'Search Results')}</span>
                    <span className="search-count">{results.length} {t('nav.found', 'found')}</span>
                  </div>
                  {results.map((p, i) => (
                    <Link
                      key={p.id}
                      to={`/products/${p.id}`}
                      className={`search-result ${i === activeIndex ? 'search-result--active' : ''}`}
                      onClick={clearSearch}
                      onMouseEnter={() => setActiveIndex(i)}
                      role="option"
                      aria-selected={i === activeIndex}
                    >
                      {p.imageUrl ? (
                        <img src={p.imageUrl} alt={p.name} loading="lazy" />
                      ) : (
                        <div className="search-result-placeholder">
                          <ShoppingBag size={18} />
                        </div>
                      )}
                      <div className="search-result-info">
                        <span className="result-name">{highlightMatch(p.name, query)}</span>
                        <span className="result-meta">
                          {p.category && <span className="result-category">{p.category}</span>}
                          {p.brand && <span className="result-brand">{p.brand}</span>}
                        </span>
                      </div>
                      <span className="result-price">${p.price?.toFixed(2)}</span>
                    </Link>
                  ))}
                  <Link
                    to={`/products?q=${encodeURIComponent(query)}`}
                    className="search-view-all"
                    onClick={clearSearch}
                  >
                    <span>{t('nav.viewAllResults', { query })}</span>
                    <ChevronRight size={14} />
                  </Link>
                </>
              ) : !searching ? (
                <div className="search-no-results">
                  <Search size={22} />
                  <span className="search-no-title">{t('nav.noResults', { query })}</span>
                  <span className="search-no-hint">{t('nav.tryDifferent', 'Try a different keyword')}</span>
                </div>
              ) : null}
            </div>
          )}
        </form>
      </div>

      {/* ── Right: Actions ── */}
      <div className="nav-right">
        {/* Language Switcher */}
        <div className="nav-lang" ref={langRef}>
          <button
            className="nav-lang-btn"
            onClick={() => setShowLang(!showLang)}
            aria-expanded={showLang}
            aria-label={t('nav.changeLanguage', 'Change language')}
          >
            <Globe size={18} />
            <span className="nav-lang-current">{currentLang.flag}</span>
            <ChevronDown size={14} className={`nav-lang-arrow ${showLang ? 'nav-lang-arrow--open' : ''}`} />
          </button>

          {showLang && (
            <div className="lang-dropdown">
              {LANGUAGES.map((lang) => (
                <button
                  key={lang.code}
                  className={`lang-dropdown-item ${i18n.language === lang.code ? 'lang-dropdown-item--active' : ''}`}
                  onClick={() => handleLanguageChange(lang.code)}
                >
                  <span className="lang-flag">{lang.flag}</span>
                  <span className="lang-name">{lang.label}</span>
                  {i18n.language === lang.code && <span className="lang-check">✓</span>}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Notifications */}
        <Link 
          to="/notifications" 
          className="nav-action-btn nav-notif-btn" 
          title={t('nav.notifications', 'Notifications')}
          aria-label={t('nav.notifications', 'Notifications')}
        >
          <Bell size={20} />
          {notificationCount > 0 && (
            <span className="nav-badge nav-badge--notif" aria-label={`${notificationCount} unread notifications`}>
              {notificationCount > 9 ? '9+' : notificationCount}
            </span>
          )}
          <span className="nav-action-label">{t('nav.notifications', 'Notifications')}</span>
        </Link>

        {/* Wishlist */}
        <Link 
          to="/wishlist" 
          className="nav-action-btn nav-wish-btn" 
          title={t('nav.wishlist')}
          aria-label={t('nav.wishlist')}
        >
          <Heart size={20} />
          {wishlist.length > 0 && (
            <span className="nav-badge nav-badge--wish" aria-label={`${wishlist.length} items in wishlist`}>
              {wishlist.length}
            </span>
          )}
          <span className="nav-action-label">{t('nav.wishlist')}</span>
        </Link>

        {/* Cart */}
        <Link 
          to="/cart" 
          className="nav-action-btn nav-cart-btn" 
          title={t('nav.cart')}
          aria-label={t('nav.cart')}
        >
          <ShoppingBag size={20} />
          {cart.itemCount > 0 && (
            <span className="nav-badge nav-badge--cart" aria-label={`${cart.itemCount} items in cart`}>
              {cart.itemCount}
            </span>
          )}
          <span className="nav-action-label">{t('nav.cart')}</span>
        </Link>

        {/* Divider */}
        <div className="nav-divider" aria-hidden="true" />

        {/* User Menu */}
        {isAuthenticated ? (
          <div className="nav-user" ref={userRef}>
            <button
              className="nav-user-trigger"
              onClick={() => setShowUser(!showUser)}
              aria-expanded={showUser}
              aria-label={t('nav.accountMenu', 'Account menu')}
            >
              <div className="nav-user-avatar" aria-hidden="true">
                {user?.fullName?.[0]?.toUpperCase() || 'U'}
              </div>
              <div className="nav-user-text">
                <span className="nav-user-name">{user?.fullName?.split(' ')[0] || t('nav.account')}</span>
              </div>
            </button>

            {showUser && (
              <div className="user-dropdown" role="menu">
                {/* Profile header */}
                <div className="user-dropdown-header">
                  <div className="user-dropdown-avatar" aria-hidden="true">
                    {user?.fullName?.[0]?.toUpperCase() || 'U'}
                  </div>
                  <div className="user-dropdown-info">
                    <p className="user-dropdown-name">{user?.fullName}</p>
                    <p className="user-dropdown-email">{user?.email}</p>
                  </div>
                </div>

                <div className="dropdown-divider" aria-hidden="true" />

                <div className="dropdown-section" role="none">
                  <Link to="/account" className="dropdown-item" onClick={() => setShowUser(false)} role="menuitem">
                    <User size={16} aria-hidden="true" />
                    <span>{t('nav.account')}</span>
                    <ChevronRight size={14} className="dropdown-item-arrow" aria-hidden="true" />
                  </Link>
                  <Link to="/orders" className="dropdown-item" onClick={() => setShowUser(false)} role="menuitem">
                    <Package size={16} aria-hidden="true" />
                    <span>{t('nav.orders')}</span>
                    <ChevronRight size={14} className="dropdown-item-arrow" aria-hidden="true" />
                  </Link>
                  <Link to="/wishlist" className="dropdown-item" onClick={() => setShowUser(false)} role="menuitem">
                    <Heart size={16} aria-hidden="true" />
                    <span>{t('nav.wishlist')}</span>
                    <ChevronRight size={14} className="dropdown-item-arrow" aria-hidden="true" />
                  </Link>
                  <Link to="/settings" className="dropdown-item" onClick={() => setShowUser(false)} role="menuitem">
                    <Settings size={16} aria-hidden="true" />
                    <span>{t('nav.settings')}</span>
                    <ChevronRight size={14} className="dropdown-item-arrow" aria-hidden="true" />
                  </Link>
                </div>

                <div className="dropdown-divider" aria-hidden="true" />

                <div className="dropdown-section" role="none">
                  <button
                    className="dropdown-item dropdown-item--danger"
                    onClick={() => { logout(); setShowUser(false); navigate('/'); }}
                    role="menuitem"
                  >
                    <LogOut size={16} aria-hidden="true" />
                    <span>{t('nav.logout')}</span>
                  </button>
                </div>
              </div>
            )}
          </div>
        ) : (
          <Link to="/login" className="nav-login-btn">
            <User size={18} aria-hidden="true" />
            <span>{t('nav.login')}</span>
          </Link>
        )}
      </div>
    </nav>
  );
}
